#!/usr/bin/env bash
# Generated By: Claude Code (Claude Opus 4.7)
# Bootstrap the .tmp-review-findings/ workspace at the project root.
#
# WIPES the workspace on every invocation to ensure each /review run starts
# from a clean slate — stale per-agent JSON, prior consolidated sets, and old
# validation batches must not leak into the next run's consolidation.
#
# Honors PROJECT_ROOT env var when set (used by tests); defaults to PWD.

set -euo pipefail

ROOT="${PROJECT_ROOT:-$PWD}"
WORK_DIR="$ROOT/.tmp-review-findings"

# Wipe and recreate from scratch.
rm -rf "$WORK_DIR"
mkdir -p "$WORK_DIR/raw"
mkdir -p "$WORK_DIR/validation"

# Write the .gitignore as a bare '*' with no trailing newline.
printf '*' > "$WORK_DIR/.gitignore"

echo "bootstrap: $WORK_DIR ready (wiped)"
